class Solution(object):
    def validStrings(self, n):
        result = []
        def backtrack(s):
            if len(s) == n:
                result.append(s)
                return
            # Can always append '1'
            backtrack(s + '1')
            # Can only append '0' if last char is '1' (or string is empty)
            if not s or s[-1] == '1':
                backtrack(s + '0')
        backtrack('')
        return result
